<template>
  <div class="question-box-pdf" v-show="questionShow" >
    <div v-html="previewHtml"
         ref="renderQuestion"></div>
  </div>
</template>

<script>
export default {
  name: "question",
  data () {
    return {
      previewHtml: "",
      questionShow:false
      
    };
  },
  props: ["questionCont", "isParse","len"],
  mounted () {
    this.renderQsDom();
  },
  watch: {
    isParse (val) {
      this.renderQsDom();
    },
    questionCont () {
      this.renderQsDom();
    }
  },
  methods: {
    renderQsDom () {
      this.questionShow = false;
      console.log("renderQsDom", this.isParse)
      let config = {
        analyzeVersion: 2,
        hideSource: true,
        hideDifficulty: true,
        excludeLogicToAutoLayout: [5],
        labels: {
          answer: "答案",
          analyze: "解析",
          queId: "ID",
        },
      };
      this.previewHtml = window.TalqsTemplate.render(this.questionCont, config);
      this.$nextTick(() => {
        window.MathJax.Hub.Queue(["Typeset", window.MathJax.Hub, this.$refs.renderQuestion], () => {
          window.pdfQuestionTotal++
          window.TalqsTemplate.autoLayout();
          this.$nextTick(() => {
          if (this.$refs.renderQuestion) {
            if (this.isParse) {
              this.$refs.renderQuestion.querySelector('.talqs_analyze_group').style.display = 'block'
            } else {
              this.$refs.renderQuestion.querySelector('.talqs_analyze_group').style.display = 'none'
            }
            this.$refs.renderQuestion.querySelector('.talqs_id').style.display = 'none'
          }
           this.questionShow = true;
           if(window.pdfQuestionTotal === this.len){
            window.renderdone = true
           }
          })
        });
      });
    },
  },
};
</script>
