
import { ref, onMounted,nextTick } from 'vue';
import { getUrlParam } from '@/utils/index';
import { ResultList } from './types/index';
import api from './service/api';
export default {
  name: 'nodePdf',
  components: {
  },
  setup () {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const note_list = ref([] as any)
    const title = ref('')
    const courseName = ref('')
    const noData = ref(false)
    const getInitData = ()=>{
      const token = getUrlParam('token') || ''
      const plan_id = getUrlParam('plan_id') || ''
      const lesson_id = getUrlParam('lesson_id') || ''
      const module_id = getUrlParam('module_id') || ''
      const media_id = getUrlParam('media_id') || ''
      api.getNoteList({
        token:decodeURIComponent(token),
        plan_id:plan_id,
        lesson_id:lesson_id,
        module_id:module_id,
        media_id:media_id,
      }).then((res:ResultList)=>{
        if(res.data.errcode === 0 && res.data.data){
          if(res.data.data.note_list&&res.data.data.note_list.length>0){
            note_list.value = res.data.data.note_list
            title.value = res.data.data.title
            courseName.value = res.data.data.course_name
            window.ConnectWebViewBridgeSDK.showShareNoteButton({});
            nextTick(() => {
              window.renderdone = true
            })
          }else{
            noData.value = true
          }
        }else{
          noData.value = true
        }
      });
    }
    onMounted(() => {
      getInitData()
    });
    return {
      title,
      courseName,
      noData,
      note_list
    }
  }
}
