
import { onMounted, reactive, ref, onBeforeUnmount } from 'vue';
import { getUrlParam } from '@/utils/index';
import { getyyyymmdd, getmmdd } from '../../utils/time';
import question from './components/question.vue'
import { List, Checkbox, CheckboxGroup } from 'vant'
import api from './api';
export default {
  name: 'bookErrors',
  components: {
    question,
    List,
    Checkbox,
    CheckboxGroup
  },
  setup() {
    let subjectName = decodeURIComponent(getUrlParam('subject_name') as string)
    subjectName = subjectName !== 'null' ? subjectName : '数学'
    const allOriginData: any = reactive([])
    const questionList: any = reactive([])
    console.log(typeof subjectName, 'subjectName 9999')
    const time = new Date().getTime()
    const today = getyyyymmdd(time)
    const noData = ref(false)
    const onePageData = ref(false)
    const loading = ref(false)
    const finished = ref(false)
    const page = ref(1)
    const showExport = ref(true)
    const checked: any = ref([])
    const yesterDay = getyyyymmdd(time - 24 * 60 * 60 * 1000)
    const getInitData = async () => {
      const token = getUrlParam('token') || ''
      // const token = 'tal173RbouzB77tkdCpTJ329DbSljGoMgytUW3qY_axr9W-YWfbZmqGEKRr82-VO5oMU7B3-DIne07xVp3enGEdeiU7maxVt_-uhHGj36xgR-DWFSUDM2Ig7RLv2Q5iXBo-IPC01yse1_klOiCDzRdOQy86ZKXw4M8BwN0J6xU6VZk1bYml'
      const subject = getUrlParam('subject_id') || '1'
      const grade = getUrlParam('grade_id') || '1'
      console.log(token, subject, grade)
      noData.value = false
      onePageData.value = false
      if (loading.value) return
      loading.value = true

      let res: any = { data: {} }
      if (!finished.value) {
         try {
          res = await api.getBookList({ token: decodeURIComponent(token), subject, grade, page: page.value, page_size: 10 })
        } catch (err) {
          console.log(err)
        }
      }
      if (res.data.errcode === 0) {
        loading.value = false
        let resData = res.data.data
        allOriginData.push(...resData)
        // questionList.value = []
        questionList.splice(0, questionList.length)
        allOriginData.map((item: any) => {
          const listDate = Array.from(questionList, ({ date }) => date)
          if (listDate.includes(item.date)) {
            const idx = questionList.findIndex((val: any) => val.date === item.date)
            questionList[idx].data.push(item)
          } else {
            questionList.push({date: item.date, data: [item]})
          }
        })
        questionList.sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime())
        questionList.map((item: any) => {
          if (item.date === today) {
            item.date = '今天'
          } else if (item.date === yesterDay) {
            item.date = '昨天'
          } else {
            item.date = getmmdd(new Date(item.date).getTime())
          }
          return item
        })
        if (page.value === 1) {
          if (resData.length === 0) {
            noData.value = true
          } else if (resData.length < 10) {
            onePageData.value = true
          } else {
            noData.value = false
            onePageData.value = false
          }
        }
        page.value++
        if (resData.length === 0) {
          finished.value = true
        }
        console.log(questionList, page.value, '哈哈哈')
      }
    }
    const onLoad = async () => {
      await getInitData()
    }
    const clickxExport = () => {
      showExport.value = false
    }
    const allSelect = () => {
      checked.value = Array.from(allOriginData, ({ question_id, id }) => `${id}&${question_id}`)
    }
    const cancelAllSelect = () => {
      checked.value = []
    }
    const cancel = () => {
      checked.value = []
      showExport.value = true
    }
    const checkboxgroupChange = (names: any) => {
      // console.log(names)
    }
    const getPreviewQrcode = () => {
      if (checked.value.length > 0) {
        let newList: any = []
        checked.value.map((item: any) => {
          newList.push(item.split('&')[1])
        })
        window.ConnectWebViewBridgeSDK.getPreviewQrcode(newList)
      }
    }
    const jumpWrongQuesDetail = (list: any, idx: number) => {
      if (!showExport.value) return
      let newList: any = []
      list.map((item: any) => {
        let obj = Object.assign({}, item)
        delete obj.question_info
        newList.push(obj)
      })
      window.ConnectWebViewBridgeSDK.jumpWrongQuestionDetail({questionList: newList, clickOrder: idx})
    }
    onMounted(async() => {
      await getInitData()
    })
    return {
      allOriginData,
      subjectName,
      questionList,
      onePageData,
      noData,
      checked,
      showExport,
      loading,
      finished,
      onLoad,
      clickxExport,
      allSelect,
      cancel,
      checkboxgroupChange,
      cancelAllSelect,
      getPreviewQrcode,
      jumpWrongQuesDetail
    }
  }
}
