
import { ref, onMounted } from 'vue';
import questionTypes from './components/questionTypes.vue'
import { loadScript, getUrlParam } from '@/utils/index';
import { ResultList } from './types/index';
import api from './service/api';
export default {
  name: 'nodePdf',
  components: {
    questionTypes
  },
  setup () {
    const getData = ref()
    const done = ref(false)
    const getInitData = ()=>{
      const token = getUrlParam('token') || ''
      const question_ids = getUrlParam('question_ids') || ''
      api.getTalTemp({question_ids:question_ids,token:decodeURIComponent(token)}).then((res:ResultList)=>{
        if(res.data.errcode === 0){
          if(res.data.data) getData.value = res.data.data
        }
      });
    }
    onMounted(() => {
      getInitData()
    });
    return {
      done,
      getData
    }
  }
}
